fn fibonacci(n: Number) -> [Number] {
    if n <= 0 { return [] }
    if n == 1 { return [0] }
    if n == 2 { return [0, 1] }
    seq = [0, 1]
    for i in range(2, n) {
        next = get(seq, -1) + get(seq, -2)
        seq = append(seq, next)
    }
    return seq
}
entry main(x: Text) { return fibonacci(10) }

