pure fn percentile_of(value: Number, sorted_list: [Number]) -> Number {
    rank = 0
    for n in sorted_list {
        if n <= value { rank = rank + 1 }
    }
    return (rank + 1) / length(sorted_list)
}
entry main(x: Text) {
