pure fn mean(nums: [Number]) -> Number {
    total = 0
    for n in nums { total = total + n }
    return total / length(nums)
}
pure fn variance(nums: [Number]) -> Number {
    avg = mean(nums)
    total = 0
    for n in nums { total = total + pow(n - avg, 2) }
    return total / length(nums)
}
pure fn stdev(nums: [Number]) -> Number {
    return sqrt(variance(nums))
}
entry main(x: Text) {
    nums = [10, 12, 23, 23, 16, 23, 21, 16]
    std_dev = stdev(nums)
    if std_dev > 5 { return join([to_text(std_dev), " — highly variable"], "") }
    return join([to_text(std_dev), " — not highly variable"], "")
}

