    return join([to_text(sorted), " | ", describe_pattern(sorted)], "")
}

fn fibonacci(n: Number) -> [Number] {
    if n <= 0 { return [] }
    if n == 1 { return [0] }
    if n == 2 { return [0, 1] }
    seq = [0, 1]
    for i in range(2, n) {
        next = get(seq, -1) + get(seq, -2)
        seq = append(seq, next)
    }
    return seq
}

fn golden_ratio_approx(seq: [Number]) -> Number {
    return round(divide(get(seq, -1), get(seq, -2)), 2)
}

entry main(x: Text) {
    fib = fibonacci(8)
    ratio = golden_ratio_approx(fib)
    return join([to_text(fib), " golden_ratio: ", to_text(ratio)], "")
}

